<h1 class="h5 mb-3">Pagos</h1>
<form class="row g-2 mb-3"><div class="col-md-3"><input type="date" name="desde" class="form-control" value="<?= e($filtros['desde']) ?>"></div><div class="col-md-3"><input type="date" name="hasta" class="form-control" value="<?= e($filtros['hasta']) ?>"></div><div class="col-md-3"><select name="estado" class="form-select"><option value="">Todos estados</option><?php foreach(['pendiente','aprobado','rechazado','anulado'] as $est): ?><option value="<?= $est ?>" <?= $filtros['estado']===$est?'selected':'' ?>><?= $est ?></option><?php endforeach; ?></select></div><div class="col-md-3"><button class="btn btn-outline-primary w-100">Filtrar</button></div></form>
<div class="card"><div class="table-responsive" style="overflow: visible;"><table class="table table-sm table-hover mb-0 tabla-admin"><thead><tr><th>Empresa</th><th>Plan</th><th>Monto</th><th>Frecuencia</th><th>Método</th><th>Estado</th><th>Referencia</th><th>Fecha</th></tr></thead><tbody><?php foreach($pagos as $p): ?><tr><td><?= e($p['empresa']) ?></td><td><?= e($p['plan'] ?? '-') ?></td><td>$<?= number_format((float)$p['monto'],0,',','.') ?> <?= e($p['moneda']) ?></td><td><?= e($p['frecuencia'] ?? '-') ?></td><td><?= e($p['metodo']) ?></td><td><?= e($p['estado']) ?></td><td><?= e($p['referencia_externa']) ?></td><td><?= e($p['fecha_pago']) ?></td></tr><?php endforeach; ?></tbody></table></div></div>
